import math

def is_prime(n: int) -> bool:
    """Returns True if n is a prime number, False otherwise."""
    # Step 1: Handle edge cases for n <= 1
    if n <= 1:
        return False
    # Step 2: Handle smallest prime
    if n == 2:
        return True
    # Step 3: Eliminate even numbers greater than 2
    if n % 2 == 0:
        return False

    # Step 4: Efficiently check odd divisors up to sqrt(n)
    # Using trial division with a step of 2 is sufficient for n up to 10^7
    # as sqrt(10^7) is approx 3162, which is a very small number of iterations.
    limit = int(math.isqrt(n))
    for i in range(3, limit + 1, 2):
        if n % i == 0:
            return False

    return True

def is_prime(n: int) -> bool:
    """Returns True if n is a prime number, False otherwise."""
    # Handle edge cases: n <= 1 are not prime
    if n <= 1:
        return False
    # 2 and 3 are prime
    if n <= 3:
        return True
    # Eliminate even numbers and multiples of 3
    if n % 2 == 0 or n % 3 == 0:
        return False

    # Check primality using 6k +/- 1 optimization
    # This skips even numbers and multiples of 3, reducing iterations by 2/3
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

